import { describe, expect, it } from 'vitest';
import {
  createClock,
  earthSurfaceClock,
  orbitingClock,
  freeFallingClock,
  compareClocks,
  clockReadingAt,
  clockIsDaylight,
  clockElapsed,
  clockReachesProperTime,
  createClockMesh,
  stormClockMesh,
} from './clock';
import { stationaryWorldline, uniformMotionWorldline } from './worldline';
import { toPicolorenzos, LIGHT_PICOLORENZO_LY } from './math';

const NOW_PLO = toPicolorenzos(new Date(Date.UTC(2026, 5, 21, 12, 0, 0)));
const ONE_DAY_PLO = 1 / Math.PI; // ~0.3183 pLo

// ─── Clock Construction ─────────────────────────────────────────────

describe('createClock', () => {
  it('stationary clock has tick rate ≈ 1', () => {
    const wl = stationaryWorldline('test', 'Test', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({ id: 'test', label: 'Test', worldline: wl });
    expect(clock.source).toBe('GnosisClock');
    expect(clock.averageTickRate).toBeCloseTo(1, 3);
    for (const reading of clock.readings) {
      expect(reading.tickRate).toBeCloseTo(1, 3);
      expect(reading.velocityFractionC).toBeCloseTo(0, 5);
    }
  });

  it('moving clock has tick rate < 1', () => {
    const speed = LIGHT_PICOLORENZO_LY * 0.5; // 0.5c in ly/pLo
    const wl = uniformMotionWorldline(
      'fast', 'Fast',
      { x: 0, y: 0, z: 0 },
      { vx: speed, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + 1, 10
    );
    const clock = createClock({ id: 'fast', label: 'Fast', worldline: wl });
    expect(clock.averageTickRate).toBeLessThan(1);
    // At 0.5c, kinematic dilation = sqrt(1 - 0.25) ≈ 0.866
    for (const reading of clock.readings.slice(1)) {
      expect(reading.kinematicTickRate).toBeCloseTo(0.866, 1);
    }
  });

  it('clock near mass has gravitational dilation', () => {
    const wl = stationaryWorldline('near-bh', 'Near BH', { x: 1e-5, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({
      id: 'near-bh',
      label: 'Near BH',
      worldline: wl,
      gravitationalBodies: [{
        id: 'bh',
        label: 'Black Hole',
        massSolar: 1e6,
        positionLy: { x: 0, y: 0, z: 0 },
      }],
    });
    for (const reading of clock.readings) {
      expect(reading.gravitationalTickRate).toBeLessThan(1);
      expect(reading.gravitationalTickRate).toBeGreaterThan(0);
    }
  });

  it('clock with observer has solar phase', () => {
    const wl = stationaryWorldline('earth', 'Earth', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + ONE_DAY_PLO, 24);
    const clock = createClock({
      id: 'earth',
      label: 'Earth',
      worldline: wl,
      observer: { latitudeDeg: 0, longitudeDeg: 0 },
    });
    const phases = clock.readings.map(r => r.solarPhase);
    expect(phases).toContain(1); // some daylight
    expect(phases).toContain(0); // some night
    expect(clock.solarHalfDay).not.toBeNull();
  });

  it('drift is zero for stationary clock in flat spacetime', () => {
    const wl = stationaryWorldline('flat', 'Flat', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({ id: 'flat', label: 'Flat', worldline: wl });
    expect(clock.totalDriftPLo).toBeCloseTo(0, 5);
  });

  it('drift is negative for moving clock (ran slow)', () => {
    const speed = LIGHT_PICOLORENZO_LY * 0.5;
    const wl = uniformMotionWorldline(
      'traveler', 'Traveler',
      { x: 0, y: 0, z: 0 },
      { vx: speed, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + 10, 20
    );
    const clock = createClock({ id: 'traveler', label: 'Traveler', worldline: wl });
    expect(clock.totalDriftPLo).toBeLessThan(0); // proper < coordinate
  });
});

// ─── Convenience Constructors ───────────────────────────────────────

describe('earthSurfaceClock', () => {
  it('creates a clock with solar phase at the equator', () => {
    const clock = earthSurfaceClock(
      'eq', 'Equator',
      { latitudeDeg: 0, longitudeDeg: 0 },
      NOW_PLO, ONE_DAY_PLO, 24
    );
    expect(clock.source).toBe('GnosisClock');
    expect(clock.readings.length).toBe(25); // 24 steps = 25 points (inclusive)
    expect(clock.solarHalfDay).not.toBeNull();
    // Should have both day and night readings
    const hasDay = clock.readings.some(r => r.solarPhase === 1);
    const hasNight = clock.readings.some(r => r.solarPhase === 0);
    expect(hasDay).toBe(true);
    expect(hasNight).toBe(true);
  });
});

describe('freeFallingClock', () => {
  it('has kinematic dilation from velocity', () => {
    const speed = LIGHT_PICOLORENZO_LY * 0.3; // 0.3c
    const clock = freeFallingClock(
      'free', 'Free',
      { x: 0, y: 0, z: 0 },
      { vx: speed, vy: 0, vz: 0 },
      NOW_PLO, 1, 10
    );
    expect(clock.averageTickRate).toBeLessThan(1);
    expect(clock.totalDriftPLo).toBeLessThan(0);
  });
});

// ─── Clock Comparison ───────────────────────────────────────────────

describe('compareClocks', () => {
  it('two stationary clocks agree', () => {
    const wlA = stationaryWorldline('a', 'A', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const wlB = stationaryWorldline('b', 'B', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clockA = createClock({ id: 'a', label: 'A', worldline: wlA });
    const clockB = createClock({ id: 'b', label: 'B', worldline: wlB });
    const comparison = compareClocks(clockA, clockB);
    expect(comparison.source).toBe('GnosisClockComparison');
    expect(comparison.properTimeDifferencePLo).toBeCloseTo(0, 5);
    expect(comparison.properTimeRatio).toBeCloseTo(1, 5);
  });

  it('moving clock falls behind stationary clock', () => {
    const wlStay = stationaryWorldline('stay', 'Stay', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 10, 20);
    const speed = LIGHT_PICOLORENZO_LY * 0.5;
    const wlMove = uniformMotionWorldline(
      'move', 'Move',
      { x: 0, y: 0, z: 0 },
      { vx: speed, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + 10, 20
    );
    const clockStay = createClock({ id: 'stay', label: 'Stay', worldline: wlStay });
    const clockMove = createClock({ id: 'move', label: 'Move', worldline: wlMove });
    const comparison = compareClocks(clockStay, clockMove);
    expect(comparison.aheadClockId).toBe('stay');
    expect(comparison.properTimeDifferencePLo).toBeGreaterThan(0);
    expect(comparison.properTimeRatio).toBeGreaterThan(1);
  });

  it('sync points show drift accumulating', () => {
    const wlStay = stationaryWorldline('stay', 'Stay', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 5, 10);
    const speed = LIGHT_PICOLORENZO_LY * 0.8;
    const wlMove = uniformMotionWorldline(
      'move', 'Move',
      { x: 0, y: 0, z: 0 },
      { vx: speed, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + 5, 10
    );
    const clockStay = createClock({ id: 'stay', label: 'Stay', worldline: wlStay });
    const clockMove = createClock({ id: 'move', label: 'Move', worldline: wlMove });
    const comparison = compareClocks(clockStay, clockMove);
    expect(comparison.syncPoints.length).toBeGreaterThan(0);
    // Drift should increase over time (stay pulls ahead)
    const drifts = comparison.syncPoints.map(sp => sp.driftPLo);
    for (let i = 1; i < drifts.length; i++) {
      expect(drifts[i]).toBeGreaterThanOrEqual(drifts[i - 1] - 0.001);
    }
  });
});

// ─── Clock Queries ──────────────────────────────────────────────────

describe('clockReadingAt', () => {
  it('interpolates between readings', () => {
    const wl = stationaryWorldline('test', 'Test', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({ id: 'test', label: 'Test', worldline: wl });
    const midpoint = NOW_PLO + 0.5;
    const reading = clockReadingAt(clock, midpoint);
    expect(reading).not.toBeNull();
    expect(reading!.coordinateTimePLo).toBeCloseTo(midpoint, 5);
    expect(reading!.properTimePLo).toBeCloseTo(0.5, 1);
  });
});

describe('clockIsDaylight', () => {
  it('returns true at noon, false at midnight', () => {
    const clock = earthSurfaceClock(
      'eq', 'Equator',
      { latitudeDeg: 0, longitudeDeg: 0 },
      NOW_PLO, ONE_DAY_PLO, 48
    );
    // NOW_PLO is at June 21 12:00 UTC, lon 0 = noon
    const atNoon = clockIsDaylight(clock, NOW_PLO);
    expect(atNoon).toBe(true);
    // Half day later = midnight
    const atMidnight = clockIsDaylight(clock, NOW_PLO + ONE_DAY_PLO / 2);
    expect(atMidnight).toBe(false);
  });

  it('returns null for clock without observer', () => {
    const wl = stationaryWorldline('no-obs', 'No Obs', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({ id: 'no-obs', label: 'No Obs', worldline: wl });
    expect(clockIsDaylight(clock, NOW_PLO)).toBeNull();
  });
});

describe('clockElapsed', () => {
  it('returns proper and coordinate time between two points', () => {
    const wl = stationaryWorldline('test', 'Test', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 10, 20);
    const clock = createClock({ id: 'test', label: 'Test', worldline: wl });
    const elapsed = clockElapsed(clock, NOW_PLO + 2, NOW_PLO + 7);
    expect(elapsed).not.toBeNull();
    expect(elapsed!.coordinateTimePLo).toBeCloseTo(5, 1);
    expect(elapsed!.properTimePLo).toBeCloseTo(5, 1);
  });
});

describe('clockReachesProperTime', () => {
  it('finds when a stationary clock reaches a given proper time', () => {
    const wl = stationaryWorldline('test', 'Test', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 10, 20);
    const clock = createClock({ id: 'test', label: 'Test', worldline: wl });
    const when = clockReachesProperTime(clock, 5);
    expect(when).not.toBeNull();
    expect(when!).toBeCloseTo(NOW_PLO + 5, 1);
  });

  it('returns null if proper time is out of range', () => {
    const wl = stationaryWorldline('test', 'Test', { x: 0, y: 0, z: 0 }, NOW_PLO, NOW_PLO + 1, 10);
    const clock = createClock({ id: 'test', label: 'Test', worldline: wl });
    expect(clockReachesProperTime(clock, 100)).toBeNull();
  });
});

// ─── Clock Mesh ─────────────────────────────────────────────────────

describe('createClockMesh', () => {
  it('produces a mesh with correct dimensions', () => {
    const mesh = createClockMesh({
      resolutionDeg: 10,
      latMin: -30,
      latMax: 30,
      lonMin: -30,
      lonMax: 30,
    });
    expect(mesh.source).toBe('GnosisClockMesh');
    expect(mesh.latCount).toBe(7); // -30, -20, -10, 0, 10, 20, 30
    expect(mesh.lonCount).toBe(6); // -30, -20, -10, 0, 10, 20
    expect(mesh.cells.length).toBe(42);
  });

  it('has lit fraction in [0, 1]', () => {
    const mesh = createClockMesh({ resolutionDeg: 30 });
    expect(mesh.litFraction).toBeGreaterThanOrEqual(0);
    expect(mesh.litFraction).toBeLessThanOrEqual(1);
  });

  it('has both day and night cells across full globe', () => {
    const mesh = createClockMesh({ resolutionDeg: 30 });
    const hasDay = mesh.cells.some(c => c.solarPhase === 1);
    const hasNight = mesh.cells.some(c => c.solarPhase === 0);
    expect(hasDay).toBe(true);
    expect(hasNight).toBe(true);
  });

  it('solar tick rates are in [0, 1]', () => {
    const mesh = createClockMesh({ resolutionDeg: 30 });
    for (const cell of mesh.cells) {
      expect(cell.solarTickRate).toBeGreaterThanOrEqual(0);
      expect(cell.solarTickRate).toBeLessThanOrEqual(1);
    }
  });

  it('relative tick rates average to ~1', () => {
    const mesh = createClockMesh({ resolutionDeg: 30 });
    const meanRelative = mesh.cells.reduce((sum, c) => sum + c.relativeTickRate, 0) / mesh.cells.length;
    expect(meanRelative).toBeCloseTo(1, 1);
  });

  it('tick rate range is > 0 (time flows differently across space)', () => {
    const mesh = createClockMesh({ resolutionDeg: 30 });
    expect(mesh.tickRateRange).toBeGreaterThan(0);
  });
});

describe('stormClockMesh', () => {
  it('creates a mesh centered on storm coordinates', () => {
    const mesh = stormClockMesh(25.0, -75.0); // Atlantic hurricane region
    expect(mesh.source).toBe('GnosisClockMesh');
    expect(mesh.latMin).toBeCloseTo(15, 0);
    expect(mesh.latMax).toBeCloseTo(35, 0);
    expect(mesh.lonMin).toBeCloseTo(-85, 0);
    expect(mesh.lonMax).toBeCloseTo(-65, 0);
    expect(mesh.cells.length).toBeGreaterThan(0);
  });

  it('has 0.5-degree default resolution', () => {
    const mesh = stormClockMesh(25.0, -75.0);
    expect(mesh.resolutionDeg).toBe(0.5);
  });
});
